SELECT 
FROM supplier_fulfillments

    AND status != 'deleted'
    AND id = #{id, jdbcType=BIGINT}
    AND supplier_id = #{supplierId, jdbcType=BIGINT}
    AND delivery_no = #{deliveryNo, jdbcType=VARCHAR}
    AND order_no = #{orderNo, jdbcType=VARCHAR}
    AND area = #{area, jdbcType=VARCHAR}
    AND warehouse_id = #{warehouseId, jdbcType=BIGINT}
    AND warehouse = #{warehouse, jdbcType=VARCHAR}
    AND customer_name = #{customerName, jdbcType=VARCHAR}
    AND customer_address = #{customerAddress, jdbcType=VARCHAR}
    AND appointment_date = #{appointmentDate, jdbcType=DATE}
    AND appointment_time = #{appointmentTime, jdbcType=VARCHAR}
    AND item_summary = #{itemSummary, jdbcType=VARCHAR}
    AND quantity = #{quantity, jdbcType=INTEGER}
    AND volume = #{volume, jdbcType=DECIMAL}
    AND weight = #{weight, jdbcType=DECIMAL}
    AND driver_name = #{driverName, jdbcType=VARCHAR}
    AND driver_mobile = #{driverMobile, jdbcType=VARCHAR}
    AND status = #{status, jdbcType=VARCHAR}
    AND shipped_at = #{shippedAt, jdbcType=TIMESTAMP}
    AND created_at = #{createdAt, jdbcType=TIMESTAMP}
    AND updated_at = #{updatedAt, jdbcType=TIMESTAMP}

ORDER BY id DESC

