FROM supplier_fulfillments

    AND status != 'deleted'
    AND order_no = #{orderNo, jdbcType=VARCHAR}
    AND status = #{status, jdbcType=VARCHAR}

ORDER BY appointment_date DESC, id DESC

    LIMIT #{offset, jdbcType=INTEGER}, #{pageSize, jdbcType=INTEGER}

